-- Migration: reconstroi ticket_categories com precos FIFA 2026 oficiais por fase
SET NOCOUNT ON;

-- 1) Limpa purchases legacy (18 compras teste) e ticket_categories
DELETE FROM dbo.purchases;
DELETE FROM dbo.ticket_categories;
DBCC CHECKIDENT ('dbo.ticket_categories', RESEED, 0);

-- 2) Insere 312 categorias (104 jogos x 3 setores) com precos por fase

-- 3) Validacao
SELECT COUNT(*) AS total FROM dbo.ticket_categories;
SELECT category, COUNT(*) AS qtd, MIN(price) AS min_preco, MAX(price) AS max_preco
 FROM dbo.ticket_categories GROUP BY category ORDER BY category;
PRINT 'Esperado: total=312, 3 categorias x precos variando por fase';
